final:
module current_sensor(  
    input wire clk,  
    input wire [3:0] current_in,  
    output reg alarm_out  
);  
    parameter THRESHOLD = 9;  

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin  
        if (current_in > THRESHOLD)  
            alarm_out <= 1'b1;  
        else  
            alarm_out <= 1'b0;  
    end  
endmodule
